// Simulate GitHub Actions `paths:` filter for desktop-ci.yml.
// GitHub matches any file changed against any pattern; if ≥1 matches → workflow runs.
import { createRequire } from "node:module";
const require = createRequire(
  "/Users/jeevanpillay/Code/@lightfastai/lightfast-wt-desktop-pre-release/node_modules/.pnpm/picomatch@4.0.4/node_modules/picomatch/package.json",
);
const picomatch = require("picomatch");

const PATTERNS = [
  "apps/desktop/**",
  "packages/app-trpc/**",
  "packages/ui/**",
  "packages/lib/**",
  "pnpm-lock.yaml",
  "pnpm-workspace.yaml",
  ".github/workflows/desktop-ci.yml",
];

const matchers = PATTERNS.map((p) =>
  picomatch(p, { dot: true, nocomment: true }),
);

function triggers(files) {
  return files.some((f) => matchers.some((m) => m(f)));
}

const cases = [
  {
    name: "Desktop main touch",
    files: ["apps/desktop/src/main/index.ts"],
    expect: true,
  },
  {
    name: "www-only",
    files: ["apps/www/src/app/page.tsx"],
    expect: false,
  },
  {
    name: "packages/ui",
    files: ["packages/ui/src/components/button.tsx"],
    expect: true,
  },
  {
    name: "packages/app-trpc",
    files: ["packages/app-trpc/src/router.ts"],
    expect: true,
  },
  {
    name: "packages/lib",
    files: ["packages/lib/src/utils.ts"],
    expect: true,
  },
  {
    name: "app-only",
    files: ["apps/app/src/app/page.tsx"],
    expect: false,
  },
  {
    name: "platform-only",
    files: ["apps/platform/src/trpc/router.ts"],
    expect: false,
  },
  {
    name: "root pnpm-lock",
    files: ["pnpm-lock.yaml"],
    expect: true,
  },
  {
    name: "desktop-ci workflow itself",
    files: [".github/workflows/desktop-ci.yml"],
    expect: true,
  },
  {
    name: "different workflow",
    files: [".github/workflows/ci.yml"],
    expect: false,
  },
  {
    name: "mixed: www + desktop",
    files: ["apps/www/src/page.tsx", "apps/desktop/src/main/index.ts"],
    expect: true,
  },
  {
    name: "desktop nested deep",
    files: ["apps/desktop/src/renderer/src/react/entry.tsx"],
    expect: true,
  },
];

let pass = 0;
let fail = 0;
for (const c of cases) {
  const got = triggers(c.files);
  const ok = got === c.expect;
  if (ok) pass++;
  else fail++;
  const status = ok ? "PASS" : "FAIL";
  console.log(
    `${status}  ${c.name} — expected=${c.expect} got=${got}  files=${JSON.stringify(c.files)}`,
  );
}
console.log(`\n${pass}/${pass + fail} passed`);
process.exit(fail ? 1 : 0);

