ok(hasCheckout, "prepare job checks out repo (needed for git tag -l)");

const coPrepareCheckout = prepareSteps.find((s) => String(s.uses ?? "").startsWith("actions/checkout@v4"));
ok(coPrepareCheckout?.with?.["fetch-depth"] === 0, "prepare checkout fetch-depth: 0 (full history for tag sort)");

