const strategy = buildJob?.strategy?.matrix ?? {};
const arches = strategy.arch ?? strategy.architecture ?? [];
const archesFlat = Array.isArray(arches) ? arches.map(String) : [];
ok(archesFlat.includes("arm64") && archesFlat.includes("x64"),
   `matrix covers arm64 + x64 (got: ${JSON.stringify(archesFlat)})`);

console.log(fails === 0 ? "\nALL PASS" : `\n${fails} FAIL`);
process.exit(fails ? 1 : 0);

